import React, { useEffect } from 'react';
import { ExternalLink, Github } from 'lucide-react';
import AOS from 'aos';
import 'aos/dist/aos.css';

const Gallery = () => {
  useEffect(() => {
    AOS.init({
      duration: 900,
      once: false,
      mirror: true,
      easing: 'ease-out-cubic',
    });
  }, []);

  const projects = [
    {
      title: 'Minor Demo Project',
      category: 'Web Development',
      description:
        'UrbanWave e-commerce frontend with product listing, cart flow, and checkout simulation built with vanilla web technologies.',
      image:
        'https://images.unsplash.com/photo-1460925895917-afdab827c52f?auto=format&fit=crop&w=1200&q=80',
      tech: ['HTML', 'CSS', 'JavaScript'],
      github: 'https://github.com/sushant347/Minor-demo-Project-HTML_CSS_JS-',
      live: 'https://sushant347.github.io/Minor-demo-Project-HTML_CSS_JS-/index.html',
    },
    {
      title: 'Advanced Python',
      category: 'Python',
      description:
        'A broad collection of advanced Python assignments and notebooks focused on practical coding, data handling, and algorithmic thinking.',
      image:
        'https://images.unsplash.com/photo-1526379879527-8559ecfcaec0?auto=format&fit=crop&w=1200&q=80',
      tech: ['Python', 'Jupyter Notebook'],
      github: 'https://github.com/sushant347/Advanced-Python',
      live: 'https://github.com/sushant347/Advanced-Python',
    },
    {
      title: 'AI Car Project',
      category: 'AI/ML',
      description:
        'Self-driving car simulation where a neural network learns track navigation through iterative training and feedback.',
      image:
        'https://images.unsplash.com/photo-1493238792000-8113da705763?auto=format&fit=crop&w=1200&q=80',
      tech: ['Python', 'Neural Network', 'Pygame'],
      github: 'https://github.com/sushant347/AI_Car_Project',
      live: 'https://github.com/sushant347/AI_Car_Project',
    },
    {
      title: 'Space Invader Game',
      category: 'Game Development',
      description:
        'Arcade-style space shooter rebuilt with Python and Pygame, including wave progression, score tracking, and fluid controls.',
      image:
        'https://images.unsplash.com/photo-1511512578047-dfb367046420?auto=format&fit=crop&w=1200&q=80',
      tech: ['Python', 'Pygame'],
      github: 'https://github.com/sushant347/Space-Invadar-Game',
      live: 'https://github.com/sushant347/Space-Invadar-Game',
    },
    {
      title: 'Snake Game',
      category: 'Game Development',
      description:
        'Classic Snake game featuring responsive keyboard controls, collision logic, score persistence, and progressive difficulty.',
      image:
        'https://images.unsplash.com/photo-1542751371-adc38448a05e?auto=format&fit=crop&w=1200&q=80',
      tech: ['Python', 'Pygame'],
      github: 'https://github.com/sushant347/Snake-Game',
      live: 'https://github.com/sushant347/Snake-Game',
    },
  ];

  return (
    <section
      id="gallery"
      className="relative min-h-screen py-20 sm:py-24 px-4 sm:px-6 overflow-hidden"
      style={{ background: 'var(--bg-primary)' }}
    >
      <div className="absolute inset-0 pointer-events-none overflow-hidden">
        <div
          className="absolute top-[-12%] right-[-8%] w-[340px] md:w-[520px] h-[340px] md:h-[520px] rounded-full blur-[120px] opacity-20"
          style={{ background: 'var(--accent-color)' }}
        ></div>
        <div
          className="absolute bottom-[-15%] left-[-10%] w-[320px] md:w-[460px] h-[320px] md:h-[460px] rounded-full blur-[100px] opacity-15"
          style={{ background: 'var(--text-primary)' }}
        ></div>
      </div>

      <div className="relative z-10 max-w-7xl mx-auto">
        <header className="text-center mb-14" data-aos="fade-down">
          <span
            className="inline-flex px-4 py-1.5 rounded-full text-xs sm:text-sm font-semibold tracking-wider uppercase"
            style={{
              background: 'var(--bg-tertiary)',
              color: 'var(--accent-color)',
              border: '1px solid var(--border-color)',
            }}
          >
            Project Gallery
          </span>
          <h2
            className="mt-5 text-4xl md:text-6xl font-bold"
            style={{ color: 'var(--text-primary)' }}
          >
            Featured
            <span
              className="ml-3 text-transparent bg-clip-text"
              style={{
                backgroundImage: 'linear-gradient(to right, var(--accent-color), var(--accent-hover))',
              }}
            >
              Work
            </span>
          </h2>
          <p className="max-w-3xl mx-auto mt-5 text-base md:text-lg" style={{ color: 'var(--text-secondary)' }}>
            A curated set of projects across web development, AI, and game programming. Each project includes source code and a live/demo destination.
          </p>
        </header>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 md:gap-8">
          {projects.map((project, index) => (
            <article
              key={project.title}
              data-aos="fade-up"
              data-aos-delay={index * 100}
              className="group rounded-2xl border overflow-hidden flex flex-col transition-all duration-300 hover:-translate-y-2"
              style={{
                background: 'var(--card-bg)',
                borderColor: 'var(--border-color)',
                boxShadow: '0 12px 30px -16px var(--shadow-color)',
              }}
            >
              <div className="relative h-52 overflow-hidden">
                <img
                  src={project.image}
                  alt={project.title}
                  className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
                />
                <div
                  className="absolute inset-0"
                  style={{ background: 'linear-gradient(to top, rgba(0,0,0,0.45), rgba(0,0,0,0.05))' }}
                ></div>
                <span
                  className="absolute left-4 top-4 text-[11px] px-3 py-1 rounded-full font-semibold tracking-wide uppercase"
                  style={{
                    background: 'rgba(255,255,255,0.18)',
                    border: '1px solid rgba(255,255,255,0.35)',
                    color: '#ffffff',
                    backdropFilter: 'blur(6px)',
                  }}
                >
                  {project.category}
                </span>
              </div>

              <div className="p-5 sm:p-6 flex flex-col flex-1">
                <h3 className="text-xl font-bold" style={{ color: 'var(--text-primary)' }}>
                  {project.title}
                </h3>

                <p className="mt-3 text-sm sm:text-base leading-relaxed flex-1" style={{ color: 'var(--text-secondary)' }}>
                  {project.description}
                </p>

                <div className="mt-4 flex flex-wrap gap-2">
                  {project.tech.map((item) => (
                    <span
                      key={`${project.title}-${item}`}
                      className="text-xs font-medium px-3 py-1 rounded-full"
                      style={{
                        background: 'var(--bg-tertiary)',
                        border: '1px solid var(--border-color)',
                        color: 'var(--text-secondary)',
                      }}
                    >
                      {item}
                    </span>
                  ))}
                </div>

                <div className="mt-6 pt-5 border-t flex gap-3" style={{ borderColor: 'var(--border-color)' }}>
                  <a
                    href={project.live}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex-1 inline-flex justify-center items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold text-white transition-transform hover:scale-[1.02]"
                    style={{ background: 'var(--accent-color)' }}
                  >
                    <ExternalLink size={16} />
                    Live Demo
                  </a>
                  <a
                    href={project.github}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex-1 inline-flex justify-center items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-semibold transition-transform hover:scale-[1.02]"
                    style={{
                      background: 'var(--bg-tertiary)',
                      color: 'var(--text-primary)',
                      border: '1px solid var(--border-color)',
                    }}
                  >
                    <Github size={16} />
                    GitHub
                  </a>
                </div>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Gallery;
