import React, { useEffect, useState } from 'react';
import { Github, Instagram, Mail, Phone, ExternalLink, Download } from 'lucide-react';
import AOS from 'aos';
import 'aos/dist/aos.css';
import mePhoto from '../components/images/mee.png';

const Home = () => {
  const [currentRole, setCurrentRole] = useState('');
  const [isDeleting, setIsDeleting] = useState(false);
  const [loopNum, setLoopNum] = useState(0);
  const [typingSpeed, setTypingSpeed] = useState(150);

  const roles = [
    "Full Stack Developer",
    "UI/UX Designer",
    "Web Developer",
    "Computer Engineer"
  ];

  useEffect(() => {
    AOS.init({
      duration: 1000,
      once: false,
      mirror: true,
      easing: 'ease-out-cubic',
    });
  }, []);

  useEffect(() => {
    const handleTyping = () => {
      const i = loopNum % roles.length;
      const fullText = roles[i];

      setCurrentRole(
        isDeleting
          ? fullText.substring(0, currentRole.length - 1)
          : fullText.substring(0, currentRole.length + 1)
      );

      setTypingSpeed(isDeleting ? 50 : 150);

      if (!isDeleting && currentRole === fullText) {
        setTimeout(() => setIsDeleting(true), 2000);
      } else if (isDeleting && currentRole === '') {
        setIsDeleting(false);
        setLoopNum(loopNum + 1);
      }
    };

    const timer = setTimeout(handleTyping, typingSpeed);
    return () => clearTimeout(timer);
  }, [currentRole, isDeleting, loopNum, roles, typingSpeed]);

  const socialLinks = [
    { icon: Github, url: 'https://github.com/sushant347', label: 'GitHub' },
    { icon: Instagram, url: 'https://www.instagram.com/sushantgautam258/', label: 'Instagram' },
    { icon: Mail, url: 'mailto:sushantgautam98677@gmail.com', label: 'Email' },
    { icon: Phone, url: 'tel:+9779869465432', label: 'Phone' },
  ];

  const handleNavClick = (e, path) => {
    e.preventDefault();
    const element = document.getElementById(path.substring(1));
    if (element) {
      const offset = 80;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - offset;
      window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
    }
  };

  return (
    <section
      id="home"
      className="min-h-screen flex items-center justify-center overflow-hidden relative pt-24 lg:pt-0"
      style={{ background: 'var(--bg-primary)' }}
    >
      {/* BACKGROUND AMBIENCE (Static) */}
      <div className="absolute inset-0 w-full h-full pointer-events-none overflow-hidden">
        <div
          className="absolute top-[-10%] right-[-5%] w-[300px] md:w-[500px] h-[300px] md:h-[500px] rounded-full blur-[80px] md:blur-[120px] opacity-20"
          style={{ background: 'var(--accent-color)' }}
        ></div>
        <div
          className="absolute bottom-[-10%] left-[-10%] w-[250px] md:w-[400px] h-[250px] md:h-[400px] rounded-full blur-[80px] md:blur-[100px] opacity-10"
          style={{ background: 'var(--text-primary)' }}
        ></div>
      </div>

      <div className="max-w-7xl mx-auto px-6 w-full z-10 pb-12 lg:pb-0">
        <div className="grid lg:grid-cols-2 gap-10 lg:gap-20 items-center">

          {/* LEFT COLUMN: TEXT */}
          <div className="space-y-10 order-2 lg:order-1 flex flex-col items-center lg:items-start text-center lg:text-left">

            <div className="space-y-6 w-full">
              {/* Badge */}
              <div
                data-aos="fade-down"
                data-aos-delay="100"
                className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-semibold tracking-wider uppercase w-fit mx-auto lg:mx-0"
                style={{
                  background: 'var(--bg-tertiary)',
                  color: 'var(--accent-color)',
                  border: '1px solid var(--border-color)'
                }}
              >
                Available for work
              </div>

              {/* Name */}
              <h1
                data-aos="fade-right"
                data-aos-delay="200"
                className="text-5xl sm:text-6xl md:text-7xl lg:text-7xl font-extrabold tracking-tight leading-[1.05]"
                style={{ color: 'var(--text-primary)' }}
              >
                Sushant <br className="hidden lg:block" />
                <span className="text-transparent bg-clip-text" style={{
                  backgroundImage: 'linear-gradient(to right, var(--accent-color), var(--accent-hover))'
                }}>
                  Gautam
                </span>
              </h1>

              {/* Dynamic Roles */}
              <div
                data-aos="fade-left"
                data-aos-delay="300"
                className="min-h-[40px] md:min-h-[52px] flex items-center justify-center lg:justify-start flex-wrap gap-y-1"
              >
                <span className="text-xl md:text-3xl font-medium mr-2" style={{ color: 'var(--text-secondary)' }}>
                  I am a
                </span>
                <span
                  className="text-xl md:text-3xl font-bold"
                  style={{ color: 'var(--text-primary)' }}
                >
                  {currentRole}
                  <span className="animate-blink ml-1 inline-block w-1 h-6 md:h-8 align-middle bg-[var(--accent-color)]"></span>
                </span>
              </div>

              {/* Description */}
              <p
                data-aos="fade-left"
                data-aos-delay="400"
                className="text-lg md:text-xl leading-relaxed max-w-xl mx-auto lg:mx-0"
                style={{ color: 'var(--text-secondary)' }}
              >
                I create exceptional digital experiences through innovative web development
                and elegant design. Specialized in React, Node.js, and modern UI technologies.
              </p>
            </div>

            {/* BUTTONS */}
            <div
              data-aos="fade-up"
              data-aos-delay="600"
              className="flex flex-col sm:flex-row flex-wrap gap-4 w-full sm:w-auto justify-center lg:justify-start"
            >
              <button
                onClick={(e) => handleNavClick(e, '#contact')}
                className="flex items-center justify-center gap-2 px-8 py-3.5 md:py-4 rounded-full text-base font-bold text-white transition-all hover:scale-105 hover:shadow-[0_0_20px_rgba(0,0,0,0.2)] active:scale-95 w-full sm:w-auto"
                style={{ background: 'var(--accent-color)' }}
              >
                Contact Me <ExternalLink size={18} />
              </button>

              <button
                className="flex items-center justify-center gap-2 px-8 py-3.5 md:py-4 rounded-full text-base font-bold transition-all hover:bg-[var(--bg-secondary)] hover:scale-105 active:scale-95 w-full sm:w-auto"
                style={{
                  border: '2px solid var(--border-color)',
                  color: 'var(--text-primary)'
                }}
              >
                Download CV <Download size={18} />
              </button>
            </div>

            {/* SOCIAL LINKS */}
            <div
              data-aos="fade-up"
              data-aos-delay="800"
              className="flex items-center gap-6 pt-4 justify-center lg:justify-start w-full"
            >
              {socialLinks.map((social, index) => {
                const Icon = social.icon;
                return (
                  <a
                    key={index}
                    href={social.url}
                    className="transition-transform hover:-translate-y-1 hover:text-[var(--accent-color)] p-2 hover:bg-[var(--bg-tertiary)] rounded-full"
                    style={{ color: 'var(--text-tertiary)' }}
                  >
                    <Icon size={24} />
                  </a>
                );
              })}
            </div>

          </div>

          {/* RIGHT COLUMN: IMAGE */}
          <div
            data-aos="fade-left"
            data-aos-delay="400"
            className="relative order-1 lg:order-2 flex justify-center items-center mt-4 lg:mt-0"
          >
            {/* Gradient background blobs */}
            <div
              className="absolute top-[10%] right-[-20%] w-[300px] md:w-[500px] h-[300px] md:h-[500px] rounded-full blur-[100px] md:blur-[120px] opacity-20 -z-10"
              style={{ background: 'var(--accent-color)' }}
            ></div>
            <div
              className="absolute bottom-[5%] left-[-25%] w-[250px] md:w-[400px] h-[250px] md:h-[400px] rounded-full blur-[80px] md:blur-[100px] opacity-15 -z-10"
              style={{ background: 'var(--accent-hover)' }}
            ></div>

            <div className="relative w-full max-w-[340px] md:max-w-[460px] lg:max-w-[520px] min-h-[380px] md:min-h-[520px] lg:min-h-[620px] flex items-end justify-center">
              <img
                src={mePhoto}
                alt="Sushant Gautam"
                className="w-full h-auto max-h-[72vh] md:max-h-[76vh] lg:max-h-[82vh] object-contain object-bottom relative z-10 transition-transform duration-500 hover:scale-105 hero-photo"
              />
            </div>
          </div>

        </div>
      </div>

      <style>{`
        @keyframes blink {
          0%, 100% { opacity: 1; }
          50% { opacity: 0; }
        }
        .animate-blink {
          animation: blink 1s step-end infinite;
        }

        /* Light mode */
        .hero-photo {
          filter: drop-shadow(0 10px 30px rgba(37, 99, 235, 0.1));
        }

        /* Dark mode */
        [data-theme="dark"] .hero-photo {
          filter: drop-shadow(0 0 40px rgba(59, 130, 246, 0.25)) drop-shadow(0 20px 30px rgba(0, 0, 0, 0.4));
        }
      `}</style>
    </section>
  );
};

export default Home;